mapper.select:
SELECT rt.id, rt.owner_id, co.name AS owner_name, rt.card_id, bc.card_no_last4 AS card_no_last4, bc.bank_name AS bank_name, rt.bill_id, cb.bill_month AS bill_month, rt.reminder_type, rt.reminder_date, rt.content, rt.status, rt.handled_time, rt.handled_by, rt.create_time FROM reminder_task rt LEFT JOIN card_owner co ON co.id = rt.owner_id AND co.is_deleted = 0 LEFT JOIN bank_card bc ON bc.id = rt.card_id AND bc.is_deleted = 0 LEFT JOIN card_bill cb ON cb.id = rt.bill_id AND cb.is_deleted = 0 WHERE rt.is_deleted = 0
AND co.name LIKE CONCAT('%', #{query.ownerName}, '%')
AND rt.reminder_type = #{query.reminderType}
AND rt.status = #{query.status}
AND rt.reminder_date >= #{query.reminderDateStart}
AND rt.reminder_date <= #{query.reminderDateEnd}
ORDER BY rt.status ASC, rt.reminder_date ASC, rt.create_time DESC
